solution_code:
#include <iostream>
#include <string>

struct Character
{
    std::string name{ "Default" };
    int health{ 100 };
    int attack{ 15 };
    int defense{ 10 };
};

int main()
{
    std::string inputName;
    int inputHealth;
    std::cin >> inputName >> inputHealth;

    Character hero{ .name = inputName, .health = inputHealth };
    Character blank{};

    std::cout << hero.name << ": hp=" << hero.health
              << " atk=" << hero.attack
              << " def=" << hero.defense << '\n';

    std::cout << blank.name << ": hp=" << blank.health
              << " atk=" << blank.attack
              << " def=" << blank.defense << '\n';

    return 0;
}
